create function public.finalize_document_upload(p_upload_intent_id uuid)
returns table (
  document_id uuid,
  document_version_id uuid,
  storage_object_id uuid,
  project_id uuid,
  bucket text,
  object_path text,
  filename text
)
language plpgsql
security definer
set search_path = public
as $$
declare
  v_intent public.document_upload_intents%rowtype;
  v_storage_object_id uuid;
  v_document_id uuid;
  v_document_version_id uuid;
  v_existing_storage_object_id uuid;
  v_object_exists boolean;
begin
  if auth.uid() is null then
    raise exception 'Authentication required';
  end if;

  select *
  into v_intent
  from public.document_upload_intents
  where id = p_upload_intent_id
  for update;

  if not found then
    raise exception 'Upload intent not found';
  end if;

  if v_intent.created_by <> auth.uid() then
    raise exception 'Upload intent does not belong to current user';
  end if;

  if not public.can_write_project_content(v_intent.project_id) then
    raise exception 'Project write access required';
  end if;

  select exists (
    select 1
    from storage.objects so
    where so.bucket_id = v_intent.bucket
      and so.name = v_intent.object_path
  )
  into v_object_exists;

  if not v_object_exists then
    raise exception 'Storage object is not accessible';
  end if;

  insert into public.storage_objects (
    bucket,
    object_path,
    filename,
    mime_type,
    size_bytes,
    uploaded_by
  )
  values (
    v_intent.bucket,
    v_intent.object_path,
    v_intent.filename,
    v_intent.mime_type,
    v_intent.size_bytes,
    v_intent.created_by
  )
  on conflict (bucket, object_path) do nothing;

  select so.id
  into v_storage_object_id
  from public.storage_objects so
  where so.bucket = v_intent.bucket
    and so.object_path = v_intent.object_path;

  if v_storage_object_id is null then
    raise exception 'Storage object linkage could not be resolved';
  end if;

  if v_intent.document_id is not null then
    v_document_id := v_intent.document_id;

    select dv.id, dv.storage_object_id
    into v_document_version_id, v_existing_storage_object_id
    from public.document_versions dv
    where dv.document_id = v_document_id
      and dv.version_number = 1
    limit 1;

    if v_document_version_id is null then
      insert into public.document_versions (
        document_id,
        storage_object_id,
        version_number,
        is_current,
        created_by
      )
      values (
        v_document_id,
        v_storage_object_id,
        1,
        true,
        v_intent.created_by
      )
      returning id
      into v_document_version_id;
    elsif v_existing_storage_object_id is distinct from v_storage_object_id then
      raise exception 'Upload intent is finalized but linked document version does not match the reserved storage object';
    end if;

    update public.document_upload_intents
    set finalized_at = coalesce(finalized_at, now())
    where id = v_intent.id;

    return query
    select
      d.id,
      dv.id,
      so.id,
      d.project_id,
      so.bucket,
      so.object_path,
      so.filename
    from public.documents d
    join public.document_versions dv
      on dv.document_id = d.id
     and dv.version_number = 1
    join public.storage_objects so
      on so.id = dv.storage_object_id
    where d.id = v_document_id
      and so.bucket = v_intent.bucket
      and so.object_path = v_intent.object_path;

    if found then
      return;
    end if;

    raise exception 'Upload intent is finalized but linked document is unavailable';
  end if;

  insert into public.documents (
    project_id,
    type,
    title,
    origin,
    description,
    created_by
  )
  values (
    v_intent.project_id,
    v_intent.type,
    v_intent.title,
    'uploaded',
    v_intent.description,
    v_intent.created_by
  )
  returning id
  into v_document_id;

  insert into public.document_versions (
    document_id,
    storage_object_id,
    version_number,
    is_current,
    created_by
  )
  values (
    v_document_id,
    v_storage_object_id,
    1,
    true,
    v_intent.created_by
  )
  returning id
  into v_document_version_id;

  update public.document_upload_intents
  set document_id = v_document_id,
      finalized_at = coalesce(finalized_at, now())
  where id = v_intent.id;

  return query
  select
    d.id,
    dv.id,
    so.id,
    d.project_id,
    so.bucket,
    so.object_path,
    so.filename
  from public.documents d
  join public.document_versions dv
    on dv.document_id = d.id
   and dv.version_number = 1
  join public.storage_objects so
    on so.id = dv.storage_object_id
  where d.id = v_document_id;
end;
$$;
